def findTheLongestBalancedSubstring(s: str) -> int:
    n = len(s)
    max_len = 0
    for i in range(n):
        count_zero = count_one = 0
        for j in range(i, n):
            if s[j] == '0':
                count_zero += 1
            elif s[j] == '1':
                count_one += 1
            if count_zero == count_one:
                max_len = max(max_len, j - i + 1)
    return max_len

